function LogoRow({ hidden }: { hidden?: boolean }) {
  return (
    <div
      className="flex shrink-0 items-center gap-20 pr-20"
      aria-hidden={hidden || undefined}
    >
      {logos.map((logo) => (
        <div
          key={logo.name}
          role={hidden ? undefined : "img"}
          aria-label={hidden ? undefined : logo.name}
          className={
            (logo.cls ?? "h-7 sm:h-8") +
            " w-auto shrink-0 opacity-55 grayscale transition duration-300 hover:opacity-100 hover:grayscale-0 [&>svg]:h-full [&>svg]:w-auto"
          }
          dangerouslySetInnerHTML={{ __html: logo.svg }}
        />
      ))}
    </div>
  );
}

export function LogoMarquee() {
  return (
    <section
      aria-label="Companies Gustavo has delivered win-loss research for"
      className="border-b border-[color:var(--hairline)] bg-[color:var(--mist)] py-12"
    >
      <p className="mb-9 text-center text-xs font-semibold uppercase tracking-[0.22em] text-[#5b6b7e]">
        Win-loss research delivered for teams at
      </p>
      <div className="marquee-mask overflow-hidden">
        <div className="marquee flex w-max">
          <LogoRow />
          <LogoRow hidden />
        </div>
      </div>
    </section>
  );
}
